            if (liveReloadPossible) {
                configSweepLoop(readConfig, runTimeConfig, getRegisteredRoots(RUN_TIME), Type.RUNTIME);
            }
            // generate sweep for run time
            configSweepLoop(readConfig, runTimeConfig, getRegisteredRoots(RUN_TIME), Type.RUNTIME);
